"use client"

import { useEffect, useState } from "react"
import { useParams, useRouter } from "next/navigation"
import { AdminLayout } from "@/components/admin-layout"
import { Input } from "@/components/ui/input"
import { Button } from "@/components/ui/button"
import { api } from "@/lib/api"
import { Deal } from "@/lib/types"

export default function EditDealPage() {
  const { id } = useParams()
  const router = useRouter()

  const [deal, setDeal] = useState<Deal | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    api<Deal>(`/api/deals/${id}`)
      .then(setDeal)
      .finally(() => setLoading(false))
  }, [id])

  const updateDeal = async () => {
    if (!deal) return

    await api(`/api/deals/${id}`, {
      method: "PATCH",
      body: JSON.stringify({
        address: deal.address,
        price: deal.price,
      }),
    })

    router.push("/deals")
  }

  if (loading) {
    return (
      <AdminLayout>
        <div className="p-8">Loading…</div>
      </AdminLayout>
    )
  }

  if (!deal) {
    return (
      <AdminLayout>
        <div className="p-8 text-red-600">Deal not found</div>
      </AdminLayout>
    )
  }

  return (
    <AdminLayout>
      <div className="p-8 space-y-4 max-w-xl">
        <h1 className="text-3xl font-bold">Edit Deal</h1>

        <Input
          value={deal.address}
          onChange={(e) => setDeal({ ...deal, address: e.target.value })}
          placeholder="Address"
        />

        <Input
          type="number"
          value={deal.price}
          onChange={(e) =>
            setDeal({ ...deal, price: Number(e.target.value) })
          }
          placeholder="Purchase Price"
        />

        <div className="flex gap-2">
          <Button onClick={updateDeal}>Save</Button>
          <Button variant="outline" onClick={() => router.back()}>
            Cancel
          </Button>
        </div>
      </div>
    </AdminLayout>
  )
}
